import { type } from "arktype";

export const PayloadSchema = type(
    {
        kind: "'int'",
        value: type("string.numeric").pipe((s) => parseInt(s, 10))
    },
    "|",
    {
        kind: "'raw'",
        value: "string"
    }
);

console.log(PayloadSchema({ kind: "int", value: "42" }));
console.log(PayloadSchema({ kind: "raw", value: "42" }));
console.log(PayloadSchema({ kind: "other", value: "42" }));

